package main

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

func main() {
	// Read version.yaml
	versionYAML, err := os.ReadFile("version.yaml")
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error reading version.yaml: %v\n", err)
		os.Exit(1)
	}

	// Parse version from YAML (simple parsing, no external dependencies)
	version := parseVersion(string(versionYAML))
	if version == "" {
		fmt.Fprintf(os.Stderr, "Error: Could not find version in version.yaml\n")
		os.Exit(1)
	}

	// Generate version.go content
	versionGo := fmt.Sprintf(`package version

// Code generated by scripts/generate_version.go; DO NOT EDIT.
// This file is generated from version.yaml

// SDKVersion is the current Kronos SDK version
// Update version.yaml and run 'make generate' to change this value
const SDKVersion = "%s"
`, version)

	// Write to pkg/version/version.go
	outputPath := filepath.Join("pkg", "version", "version.go")
	if err := os.WriteFile(outputPath, []byte(versionGo), 0644); err != nil {
		fmt.Fprintf(os.Stderr, "Error writing %s: %v\n", outputPath, err)
		os.Exit(1)
	}

	fmt.Printf("✓ Generated %s with version: %s\n", outputPath, version)
}

// parseVersion extracts version from YAML content
// Simple parser that doesn't require external dependencies
func parseVersion(yaml string) string {
	lines := strings.Split(yaml, "\n")
	for _, line := range lines {
		line = strings.TrimSpace(line)
		// Skip comments and empty lines
		if line == "" || strings.HasPrefix(line, "#") {
			continue
		}
		// Look for "version: vX.Y.Z"
		if strings.HasPrefix(line, "version:") {
			parts := strings.SplitN(line, ":", 2)
			if len(parts) == 2 {
				version := strings.TrimSpace(parts[1])
				// Remove quotes if present
				version = strings.Trim(version, `"'`)
				return version
			}
		}
	}
	return ""
}
